import{_ as i,o as t,c as s,aj as o}from"./chunks/framework.RhfyOUxy.js";const h=JSON.parse('{"title":"Connecteur TopSolid Automation","description":"","frontmatter":{},"headers":[],"relativePath":"connecteur.md","filePath":"connecteur.md"}'),a={name:"connecteur.md"};function n(r,e,l,c,d,p){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="connecteur-topsolid-automation" tabindex="-1">Connecteur TopSolid Automation <a class="header-anchor" href="#connecteur-topsolid-automation" aria-label="Permalink to &quot;Connecteur TopSolid Automation&quot;">​</a></h1><p>Ce document décrit le fonctionnement du connecteur natif utilisant l&#39;API Automation de TopSolid.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>Le serveur MCP communique avec TopSolid via des <strong>Named Pipes</strong> .NET. Contrairement à l&#39;ancienne architecture utilisant un Bridge WCF (HTTP), cette connexion est directe et ne nécessite aucun processus intermédiaire.</p><h2 id="configuration-logicielle-requise" tabindex="-1">Configuration logicielle requise <a class="header-anchor" href="#configuration-logicielle-requise" aria-label="Permalink to &quot;Configuration logicielle requise&quot;">​</a></h2><ul><li><strong>TopSolid 7.15+</strong> (développé et testé sur 7.20)</li><li><strong>TopSolid.Kernel.Automating.dll</strong> : Cette DLL doit être présente dans le répertoire d&#39;installation de TopSolid.</li></ul><h2 id="initialisation" tabindex="-1">Initialisation <a class="header-anchor" href="#initialisation" aria-label="Permalink to &quot;Initialisation&quot;">​</a></h2><p>La connexion est initialisée au démarrage du serveur via la classe <code>TopSolidConnector</code>.</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> connector</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> TopSolidConnector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">connector.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Connect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><p>Le serveur tente de se connecter à une instance de TopSolid déjà ouverte. S&#39;il n&#39;en trouve pas au démarrage, il reste en attente.</p><h3 id="reconnexion-automatique-lazy" tabindex="-1">Reconnexion automatique (Lazy) <a class="header-anchor" href="#reconnexion-automatique-lazy" aria-label="Permalink to &quot;Reconnexion automatique (Lazy)&quot;">​</a></h3><p>Si TopSolid est lancé APRÈS le serveur MCP :</p><ul><li>Les outils d&#39;interrogation en direct (<code>topsolid_get_state</code>, <code>topsolid_execute_script</code>) tenteront automatiquement de se reconnecter une fois au moment de l&#39;appel.</li><li>Si la reconnexion réussit, l&#39;outil s&#39;exécute normalement.</li><li>Si elle échoue (TopSolid toujours fermé), l&#39;outil retourne un message indiquant que TopSolid n&#39;est pas connecté.</li></ul><h2 id="outils-disponibles" tabindex="-1">Outils disponibles <a class="header-anchor" href="#outils-disponibles" aria-label="Permalink to &quot;Outils disponibles&quot;">​</a></h2><h3 id="topsolid-get-state" tabindex="-1"><code>topsolid_get_state</code> <a class="header-anchor" href="#topsolid-get-state" aria-label="Permalink to &quot;`topsolid_get_state`&quot;">​</a></h3><p>Retourne le nom du document édité, son type (extension) et le projet PDM associé.</p><h3 id="topsolid-execute-script" tabindex="-1"><code>topsolid_execute_script</code> <a class="header-anchor" href="#topsolid-execute-script" aria-label="Permalink to &quot;`topsolid_execute_script`&quot;">​</a></h3><p>Compile et exécute un script C# dynamique contre l&#39;API Automation de TopSolid.</p><h4 id="fonctionnement" tabindex="-1">Fonctionnement <a class="header-anchor" href="#fonctionnement" aria-label="Permalink to &quot;Fonctionnement&quot;">​</a></h4><ul><li><strong>Compilateur</strong> : <code>Microsoft.CSharp.CSharpCodeProvider</code> (.NET 4.8).</li><li><strong>Wrapper</strong> : Le code envoyé est encapsulé dans une classe <code>DynamicScript</code> avec une méthode <code>Run()</code>.</li><li><strong>Namespaces inclus</strong> : <code>System</code>, <code>System.Collections.Generic</code>, <code>System.Linq</code>, <code>System.Text</code>, <code>System.IO</code> et <code>TopSolid.Kernel.Automating</code>.</li><li><strong>Transactions</strong> : Détection automatique des mots-clés (<code>Set</code>, <code>Create</code>, <code>SetName</code>, etc.) pour ouvrir une transaction TopSolid via <code>StartModification</code>.</li></ul><h4 id="exemple-de-script" tabindex="-1">Exemple de script <a class="header-anchor" href="#exemple-de-script" aria-label="Permalink to &quot;Exemple de script&quot;">​</a></h4><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> doc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> TopSolidHost.Documents.EditedDocument;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> elements</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> TopSolidHost.Elements.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetElements</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(doc);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> $&quot;Le document contient {</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">elements</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Count</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">} éléments.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="gestion-des-erreurs" tabindex="-1">Gestion des Erreurs <a class="header-anchor" href="#gestion-des-erreurs" aria-label="Permalink to &quot;Gestion des Erreurs&quot;">​</a></h2><p>Toutes les méthodes de <code>TopSolidConnector</code> et <code>ScriptExecutor</code> sont sécurisées par des blocs <code>try-catch</code>.</p><ul><li><strong>Erreurs de compilation</strong> : Retournées avec le numéro de ligne et le code d&#39;erreur CS.</li><li><strong>Erreurs d&#39;exécution</strong> : Capturées sous forme de <code>TargetInvocationException</code> pour rapporter l&#39;erreur interne sans crasher le serveur.</li><li><strong>Perte de connexion</strong> : Si TopSolid est fermé, l&#39;outil retourne un message standard de déconnexion.</li></ul>',25)])])}const k=i(a,[["render",n]]);export{h as __pageData,k as default};
